// MARK: - Push Token Store (AppDelegate integration required)

final class PushTokenStore {
    static let shared = PushTokenStore()
    private init() {}

    private let key = "PushTokenStore.token"
    var tokenString: String? {
        get { UserDefaults.standard.string(forKey: key) }
        set {
            if let newValue { UserDefaults.standard.set(newValue, forKey: key) }
            else { UserDefaults.standard.removeObject(forKey: key) }
        }
    }

    func update(deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02x", $0) }.joined()
        tokenString = token
    }
}

// MARK: - IAP Manager (StoreKit 1)

final class IAPManager: NSObject, SKProductsRequestDelegate, SKPaymentTransactionObserver {
    static let shared = IAPManager()

    struct PurchaseReceipt {
        let transactionId: String
        let originalTransactionId: String
        let receiptDataBase64: String
    }

    private var productsCompletion: ((Result<[SKProduct], Error>) -> Void)?
    private var purchaseCompletions: [String: (Result<PurchaseReceipt, Error>) -> Void] = [:]
    private var productsRequest: SKProductsRequest?
    private var cachedProducts: [String: SKProduct] = [:]

    private override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }

    deinit {
        SKPaymentQueue.default().remove(self)
    }

    func fetchProducts(identifiers: Set<String>, completion: @escaping (Result<[SKProduct], Error>) -> Void) {
        productsCompletion = completion
        productsRequest?.cancel()
        let req = SKProductsRequest(productIdentifiers: identifiers)
        req.delegate = self
        productsRequest = req
        req.start()
    }

    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for p in response.products { cachedProducts[p.productIdentifier] = p }
        productsCompletion?(.success(response.products))
        productsCompletion = nil
        productsRequest = nil
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        productsCompletion?(.failure(error))
        productsCompletion = nil
        productsRequest = nil
    }

    func purchase(productId: String, completion: @escaping (Result<PurchaseReceipt, Error>) -> Void) {
        guard SKPaymentQueue.canMakePayments() else {
            completion(.failure(NSError(domain: "IAP", code: 1, userInfo: [NSLocalizedDescriptionKey: "Payments not allowed on this device"])))
            return
        }

        if let product = cachedProducts[productId] {
            purchaseCompletions[productId] = completion
            SKPaymentQueue.default().add(SKPayment(product: product))
            return
        }

        fetchProducts(identifiers: [productId]) { [weak self] result in
            guard let self else { return }
            switch result {
            case .success(let products):
                guard let product = products.first(where: { $0.productIdentifier == productId }) else {
                    completion(.failure(NSError(domain: "IAP", code: 2, userInfo: [NSLocalizedDescriptionKey: "Product not found"])))
                    return
                }
                self.purchaseCompletions[productId] = completion
                SKPaymentQueue.default().add(SKPayment(product: product))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }

    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for t in transactions {
            let productId = t.payment.productIdentifier
            guard let completion = purchaseCompletions[productId] else {
                if t.transactionState == .purchased || t.transactionState == .failed || t.transactionState == .restored {
                    queue.finishTransaction(t)
                }
                continue
            }

            switch t.transactionState {
            case .purchased, .restored:
                let receiptData = (try? Data(contentsOf: Bundle.main.appStoreReceiptURL ?? URL(fileURLWithPath: ""))) ?? Data()
                let receiptBase64 = receiptData.base64EncodedString()
                let transactionId = t.transactionIdentifier ?? ""
                let originalId = t.original?.transactionIdentifier ?? transactionId
                completion(.success(PurchaseReceipt(transactionId: transactionId, originalTransactionId: originalId, receiptDataBase64: receiptBase64)))
                purchaseCompletions[productId] = nil
                queue.finishTransaction(t)

            case .failed:
                let err = t.error ?? NSError(domain: "IAP", code: 3, userInfo: [NSLocalizedDescriptionKey: "Purchase failed"])
                completion(.failure(err))
                purchaseCompletions[productId] = nil
                queue.finishTransaction(t)

            case .purchasing, .deferred:
                break
            @unknown default:
                break
            }
        }
    }
}

// MARK: - Helpers

private extension UIImage {
    func scaledDown(maxDimension: CGFloat) -> UIImage {
        guard max(size.width, size.height) > maxDimension, maxDimension > 0 else { return self }
        let scale = maxDimension / max(size.width, size.height)
        let newSize = CGSize(width: size.width * scale, height: size.height * scale)
        UIGraphicsBeginImageContextWithOptions(newSize, true, 1)
        defer { UIGraphicsEndImageContext() }
        draw(in: CGRect(origin: .zero, size: newSize))
        return UIGraphicsGetImageFromCurrentImageContext() ?? self
    }
}

private extension SKProduct {
    var localizedPrice: String? {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.locale = priceLocale
        return formatter.string(from: price)
    }
}

private extension String {
    var jsQuoted: String {
        var s = self
        s = s.replacingOccurrences(of: "\\", with: "\\\\")
        s = s.replacingOccurrences(of: "\"", with: "\\\"")
        s = s.replacingOccurrences(of: "\'", with: "\\\'")
        s = s.replacingOccurrences(of: "\n", with: "\\n")
        s = s.replacingOccurrences(of: "\r", with: "\\r")
        s = s.replacingOccurrences(of: "\u{2028}", with: "\\u2028")
        s = s.replacingOccurrences(of: "\u{2029}", with: "\\u2029")
        return "\"\(s)\""
    }
}

